    (1001, 1, '감기약 먹고 계속 졸려요', '감기약을 먹고 나면 낮 동안 너무 졸립니다. 이런 경우가 흔한가요?', NULL, 'ko', 'medicine,side-effect', 'QUESTION', '2026-04-02 10:00:00'),
    (1002, 2, 'Lan dau den benh vien Han Quoc can chuan bi gi', 'Toi sap di kham lan dau o Han Quoc. Ngoai ho chieu va the bao hiem thi can mang gi nua?', NULL, 'vi', 'hospital,first-visit', 'QUESTION', '2026-04-02 10:05:00'),
    (1003, 3, 'Zuowan zai yaofang mai ganmaoyao de tiyan', 'Zuowan qu yaofang mai ganmaoyao, yaoshi hui xian wen zhengzhuang, goutong bi xiangxiang shunli.', NULL, 'zh', 'pharmacy,review', 'REVIEW', '2026-04-02 10:10:00'),
    (1004, 4, 'Tarjima ilovasini korsatsam boladimi', 'Qabul oynasida savollar kop bolsa, tarjima ilovasini korsatsam muammo bolmaydimi?', NULL, 'uz', 'hospital,translation-app', 'QUESTION', '2026-04-02 10:15:00'),
    (1005, 5, 'Ror khio nan mak pokti mai', 'Wan ni ror khio klueap neung chuaโมง อยากรู้ว่าโรงพยาบาลที่นี่ปกติเป็นแบบนี้ไหม', NULL, 'th', 'hospital,waiting-time', 'QUESTION', '2026-04-02 10:20:00'),
    (1006, 1, '응급 증상일 때는 바로 응급실로 가세요', '가슴 통증, 호흡 곤란, 의식 저하가 있으면 커뮤니티 답변을 기다리지 말고 바로 응급실이나 119를 이용하세요.', NULL, 'ko', 'notice,emergency', 'NOTICE', '2026-04-02 10:25:00'),
    (1007, 2, 'Thuoc nay nen uong truoc hay sau bua an', 'Toa thuoc khong ghi ro, nen toi dang hoi vi so uong sai gio.', NULL, 'vi', 'medicine,dosage', 'QUESTION', '2026-04-02 10:30:00'),
    (1008, 3, 'Hanguo yiyuan chuzhen liucheng bi xiangxiang zhong shunli', 'Diyi ci qu yiyuan shi youdian jinzhang, dan guahao he wenshen liucheng dou hen qingchu.', NULL, 'zh', 'hospital,review,first-visit', 'REVIEW', '2026-04-02 10:35:00'),
    (1009, 4, 'Dori qopidagi korsatmalarni tez tushunish usuli', 'Men kamera tarjimasi bilan dozani va kuniga necha marta ichishni tekshiraman.', NULL, 'uz', 'medicine,translation-tip', 'FREE', '2026-04-02 10:40:00'),
    (1010, 5, 'Akan di khuen laeo tong kin ya jon khrop mai', 'Ton ni rusuek di khuen mak tae yang luea ya ik song wan loei langle wa cha yut eng dai mai', NULL, 'th', 'medicine,course', 'QUESTION', '2026-04-02 10:45:00'),
    (1011, 1, '처방전 종이를 잃어버렸어요', '약 봉투는 있는데 종이 처방전을 잃어버렸습니다. 다시 병원에 가야 할까요?', NULL, 'ko', 'prescription,document', 'QUESTION', '2026-04-02 10:50:00'),
    (1012, 2, 'Benh vien co nhan walk in khong', 'Toi khong dat lich truoc. Benh vien lon co nhan kham walk in khong?', NULL, 'vi', 'hospital,reservation', 'QUESTION', '2026-04-02 10:55:00'),
    (1013, 3, 'Keyi zhi jie mai zhengchang de weichang yao ma', 'Wo zhishi qingwei weitong, xiang zhidao yaofang neng bu neng zhi jie mai yao.', NULL, 'zh', 'pharmacy,otc', 'QUESTION', '2026-04-02 11:00:00'),
    (1014, 4, 'Mahalliy klinika kutganimdan yaxshi boldy', 'Kichik klinikada kutish vaqti qisqa boldy va shifokor sekin gapirdi.', NULL, 'uz', 'clinic,review', 'REVIEW', '2026-04-02 11:05:00'),
    (1015, 5, 'Khai tua ton klang khuen khuan pai thi nai', 'Tha mi khai sung ton klang khuen khuan pai hong chukchoen rue klinik wen mai', NULL, 'th', 'emergency,fever', 'QUESTION', '2026-04-02 11:10:00'),
    (1016, 1, '휴대폰 메모로 증상 보여줘도 되나요', '한국어로 길게 말하기 어려워서 증상을 메모장에 적어 보여주려고 합니다. 괜찮을까요?', NULL, 'ko', 'hospital,translation-tip', 'QUESTION', '2026-04-02 11:15:00'),
    (1017, 2, 'Can giu lai giay to nao de bao hiem thanh toan', 'Sau khi kham xong toi nen giu lai nhung giay to nao de sau nay nop bao hiem?', NULL, 'vi', 'insurance,document', 'FREE', '2026-04-02 11:20:00'),
    (1018, 3, 'Ruguo chixia qu hou pifu hongzhong yao zenme ban', 'Chi yao hou chuxian pifu hongzhong huo huxi bu shun, shi bu shi yinggai mashang qu jijiu?', NULL, 'zh', 'notice,allergy', 'NOTICE', '2026-04-02 11:25:00'),
    (1019, 4, 'Antibiotik ichgandan keyin ich ketishi odatiymi', 'Ikki kundan beri antibiotik ichyapman, qornim bezovta va ich ketmoqda. Bu odatiy holatmi?', NULL, 'uz', 'medicine,side-effect', 'QUESTION', '2026-04-02 11:30:00'),
    (1020, 5, 'Ya ton duek thi poet chang rot chiwit mak', 'Muea khuen gon chan dai raan ya ton duek chuai wai mak', NULL, 'th', 'pharmacy,review,night', 'REVIEW', '2026-04-02 11:35:00');

